let lastStampSec: number | undefined;

export const inputs = ["/zed/zed_node/pose"];
export const output = "/zed_pose_hz";

type Output = { hz: number };

export default function script(event: { message: any }): Output {
  const stamp = event.message.header.stamp;
  const currentTime = stamp.sec + stamp.nsec / 1e9;

  let hz = 0;
  if (lastStampSec !== undefined) {
    const dt = currentTime - lastStampSec;
    hz = (dt > 0 && dt < 1) ? 1.0 / dt : 0;
  }
  lastStampSec = currentTime;

  return { hz };
}

