const STATUS_MAP: Record<string, number> = {
  "INITIALIZING": 0,
  "KNOWN_MAP":    1,
  "LOOP_CLOSED":  2,
  "MAP_UPDATE":   3,
  "LOST":         4,
  "UNKNOWN":      -1,
};

export const inputs = ["/zed/spatial_memory_status"];
export const output = "/zed_mem_status_numeric";

type Output = { value: number; label: string };

export default function script(event: { message: any }): Output {
  const statusMsg = event.message.status?.[0]?.message ?? "UNKNOWN";
  return {
    value: STATUS_MAP[statusMsg] ?? -1,
    label: statusMsg,
  };
}

