export const inputs = ["/zed/zed_node/pose"];
export const output = "/zed_rpy";

type Output = { roll: number; pitch: number; yaw: number };

export default function script(event: { message: any }): Output {
  const { x, y, z, w } = event.message.pose.orientation;

  const roll  = Math.atan2(2*(w*x + y*z), 1 - 2*(x*x + y*y));
  const pitch = Math.asin(2*(w*y - z*x));
  const yaw   = Math.atan2(2*(w*z + x*y), 1 - 2*(y*y + z*z));

  const toDeg = (r: number) => r * (180 / Math.PI);

  return {
    roll:  toDeg(roll),
    pitch: toDeg(pitch),
    yaw:   toDeg(yaw),
  };
}
